PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "event_name" (
	"event_name"	TEXT,
	"tags"	TEXT
);
CREATE TABLE IF NOT EXISTS "master_inventory" (
  row_id INTEGER PRIMARY KEY,
  item_id TEXT,
  item_name TEXT,
  box_number TEXT,
  storage_location TEXT,
  event_tags TEXT NOT NULL,
  description TEXT NOT NULL,
  crew_notes TEXT,
  qty_required NUMERIC NOT NULL,
  stock_on_hand NUMERIC NOT NULL,
  count_confirmed TEXT,
  order_stock_qty NUMERIC,
  restock_comments TEXT,
  is_active INTEGER NOT NULL DEFAULT 1 CHECK (is_active IN (0, 1)), version    INTEGER NOT NULL DEFAULT 1, created_at TEXT    NOT NULL DEFAULT '1970-01-01T00:00:00Z', updated_at TEXT    NOT NULL DEFAULT '1970-01-01T00:00:00Z', updated_by TEXT    NOT NULL DEFAULT 'system', qty_flag_limit REAL, team_admin_notes TEXT DEFAULT '',
  CHECK ((item_id IS NULL AND item_name IS NULL) OR (item_id IS NOT NULL AND item_name IS NOT NULL)),
  FOREIGN KEY (item_id, item_name)
    REFERENCES item_id_list (item_id, item_name)
    ON UPDATE RESTRICT
    ON DELETE RESTRICT
);
CREATE TABLE schema_migrations (
                migration_id TEXT PRIMARY KEY,
                applied_at   TEXT NOT NULL
                             DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ','now'))
            );
CREATE TABLE roles (
  role_id   INTEGER PRIMARY KEY,
  role_name TEXT    NOT NULL UNIQUE,
  weight    INTEGER NOT NULL UNIQUE,  -- numeric ordering, do not change existing values
  label     TEXT    NOT NULL
);
CREATE TABLE users (
  user_id       INTEGER PRIMARY KEY,
  username      TEXT    NOT NULL UNIQUE COLLATE NOCASE,
  display_name  TEXT    NOT NULL,
  password_hash TEXT,                   -- bcrypt; NULL until Phase 2
  role_id       INTEGER NOT NULL
    REFERENCES roles(role_id) ON UPDATE RESTRICT ON DELETE RESTRICT,
  is_active     INTEGER NOT NULL DEFAULT 1 CHECK (is_active IN (0, 1)),
  created_at    TEXT    NOT NULL DEFAULT '1970-01-01T00:00:00Z',
  last_login_at TEXT                     -- NULL until first login
);
CREATE TABLE audit_log (
  log_id      INTEGER PRIMARY KEY,
  table_name  TEXT    NOT NULL,
  row_ref     TEXT    NOT NULL,           -- e.g. "row_id=42" or "item_id=ABC01"
  action      TEXT    NOT NULL,           -- UPDATE | INSERT | TOGGLE | LINK
  field_name  TEXT,                       -- NULL for whole-row actions
  old_value   TEXT,
  new_value   TEXT,
  changed_by  TEXT    NOT NULL DEFAULT 'system',  -- username or IP until Phase 2
  changed_at  TEXT    NOT NULL DEFAULT '1970-01-01T00:00:00Z',
  session_id  TEXT,                       -- UUID correlating multi-field saves
  device_hint TEXT                        -- remote IP or device label
);
CREATE TABLE event_tag_catalog (
    tag_name TEXT PRIMARY KEY,
    -- Canonical uppercase token, e.g., REAL1, REALWOMAN, NEEDED, etc.
    
    status TEXT NOT NULL DEFAULT 'Active'
        CHECK (status IN ('Active', 'Inactive')),
    -- Active: selectable in UI. Inactive: readable in old records, blocked for new selection.
    
    description TEXT,
    -- Human definition: why this tag exists, when to use it.
    
    sort_order INTEGER,
    -- Explicit display order in UI (NULL = alphabetic fallback).
    
    owner TEXT,
    -- Steward name or role accountable for tag definition.
    
    created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ','now')),
    updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ','now')),
    updated_by TEXT
    -- Lifecycle and audit trail linkage.
, version INTEGER NOT NULL DEFAULT 1, created_by TEXT);
CREATE TABLE ui_rule_settings (
            rule_key   TEXT PRIMARY KEY,
            value_text TEXT NOT NULL,
            updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ','now')),
            updated_by TEXT,
            version    INTEGER NOT NULL DEFAULT 1
        );
CREATE TABLE IF NOT EXISTS "item_id_list" (
  item_id TEXT PRIMARY KEY,
  status TEXT NOT NULL CHECK (status IN ('Active','Inactive')),
  item_name TEXT NOT NULL, version INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL DEFAULT '1970-01-01T00:00:00Z', updated_at TEXT NOT NULL DEFAULT '1970-01-01T00:00:00Z', updated_by TEXT NOT NULL DEFAULT 'system',
  UNIQUE(item_id, item_name)
);
CREATE TABLE box_id_list (
  box_key    TEXT PRIMARY KEY,
  box_number TEXT NOT NULL UNIQUE,
  box_id     TEXT UNIQUE,
  box_label  TEXT,
  box_type   TEXT,
  status     TEXT NOT NULL DEFAULT 'Active' CHECK (status IN ('Active', 'Inactive')),
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ','now')),
  updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ','now')),
  updated_by TEXT NOT NULL DEFAULT 'system',
  version    INTEGER NOT NULL DEFAULT 1
);
CREATE TRIGGER trg_master_inventory_no_delete
BEFORE DELETE ON master_inventory
BEGIN
  SELECT RAISE(ABORT, 'Delete blocked: master_inventory rows are retained. Use is_active toggle.');
END;
CREATE TRIGGER trg_audit_log_no_delete
BEFORE DELETE ON audit_log
BEGIN
  SELECT RAISE(ABORT, 'audit_log rows are immutable and cannot be deleted.');
END;
CREATE TRIGGER trg_audit_log_no_update
BEFORE UPDATE ON audit_log
BEGIN
  SELECT RAISE(ABORT, 'audit_log rows are immutable and cannot be updated.');
END;
CREATE TRIGGER trg_master_inventory_required_insert
BEFORE INSERT ON master_inventory
BEGIN
  SELECT CASE
    WHEN NEW.item_id IS NULL OR TRIM(NEW.item_id) = ''
      THEN RAISE(ABORT, 'item_id is required')
  END;

  SELECT CASE
    WHEN NEW.item_name IS NULL OR TRIM(NEW.item_name) = ''
      THEN RAISE(ABORT, 'item_name is required')
  END;

  SELECT CASE
    WHEN NEW.box_number IS NULL OR TRIM(NEW.box_number) = ''
      THEN RAISE(ABORT, 'box_number is required')
  END;

  SELECT CASE
    WHEN NEW.storage_location IS NULL OR TRIM(NEW.storage_location) = ''
      THEN RAISE(ABORT, 'storage_location is required')
  END;

  SELECT CASE
    WHEN NEW.event_tags IS NULL OR TRIM(NEW.event_tags) = ''
      THEN RAISE(ABORT, 'event_tags is required')
  END;

  SELECT CASE
    WHEN NEW.description IS NULL OR TRIM(NEW.description) = ''
      THEN RAISE(ABORT, 'description is required')
  END;

  SELECT CASE
    WHEN NEW.qty_required IS NULL
      THEN RAISE(ABORT, 'qty_required is required')
  END;

  SELECT CASE
    WHEN NEW.stock_on_hand IS NULL
      THEN RAISE(ABORT, 'stock_on_hand is required')
  END;
END;
CREATE TRIGGER trg_master_inventory_required_update
BEFORE UPDATE ON master_inventory
BEGIN
  SELECT CASE
    WHEN NEW.item_id IS NULL OR TRIM(NEW.item_id) = ''
      THEN RAISE(ABORT, 'item_id is required')
  END;

  SELECT CASE
    WHEN NEW.item_name IS NULL OR TRIM(NEW.item_name) = ''
      THEN RAISE(ABORT, 'item_name is required')
  END;

  SELECT CASE
    WHEN NEW.box_number IS NULL OR TRIM(NEW.box_number) = ''
      THEN RAISE(ABORT, 'box_number is required')
  END;

  SELECT CASE
    WHEN NEW.storage_location IS NULL OR TRIM(NEW.storage_location) = ''
      THEN RAISE(ABORT, 'storage_location is required')
  END;

  SELECT CASE
    WHEN NEW.event_tags IS NULL OR TRIM(NEW.event_tags) = ''
      THEN RAISE(ABORT, 'event_tags is required')
  END;

  SELECT CASE
    WHEN NEW.description IS NULL OR TRIM(NEW.description) = ''
      THEN RAISE(ABORT, 'description is required')
  END;

  SELECT CASE
    WHEN NEW.qty_required IS NULL
      THEN RAISE(ABORT, 'qty_required is required')
  END;

  SELECT CASE
    WHEN NEW.stock_on_hand IS NULL
      THEN RAISE(ABORT, 'stock_on_hand is required')
  END;
END;
CREATE INDEX idx_master_inventory_item_name ON master_inventory(item_name);
CREATE INDEX idx_master_inventory_item_id ON master_inventory(item_id);
CREATE INDEX idx_master_inventory_active_box ON master_inventory(is_active, box_number);
CREATE INDEX idx_users_username ON users(username);
CREATE INDEX idx_users_role_id  ON users(role_id);
CREATE INDEX idx_audit_table_row  ON audit_log(table_name, row_ref);
CREATE INDEX idx_audit_changed_by ON audit_log(changed_by);
CREATE INDEX idx_audit_changed_at ON audit_log(changed_at);
CREATE INDEX idx_event_tag_catalog_status 
    ON event_tag_catalog(status, sort_order);
CREATE INDEX idx_item_id_list_item_name ON item_id_list(item_name);
CREATE INDEX idx_item_id_list_status ON item_id_list(status);
COMMIT;
